Here's a complete example:

**XAML**
```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem}"
                    SelectionChangedCommand="{Binding SelectionChangedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="*,Auto">
                    <Label Text="{Binding Name}" FontSize="16" />
                    <Label Grid.Column="1" Text="{Binding Status}"
                           TextColor="Gray" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
    </CollectionView>
</RefreshView>
```

**ViewModel**
```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private bool _isRefreshing;

    [ObservableProperty]
    private Item? _selectedItem;

    public ObservableCollection<Item> Items { get; } = new();

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            Items.Clear();
            foreach (var item in data)
                Items.Add(item);
        }
        finally
        {
            IsRefreshing = false; // stops the spinner
        }
    }

    [RelayCommand]
    private async Task SelectionChangedAsync()
    {
        if (SelectedItem is null) return;

        await _nav.GoToAsync(nameof(DetailPage),
            new Dictionary<string, object> { ["Item"] = SelectedItem });

        SelectedItem = null; // reset so the same item can be re-selected
    }
}
```

**Key bindings explained:**

| Binding | Purpose |
|---|---|
| `IsRefreshing` → `RefreshView.IsRefreshing` | Two-way: the view sets it `true` on pull; you set it `false` to stop the spinner |
| `RefreshCommand` → `RefreshView.Command` | Fires when the user pulls down |
| `SelectionMode="Single"` | Allows exactly one item selected at a time |
| `SelectedItem` → `CollectionView.SelectedItem` | Two-way: tracks current selection; set to `null` after navigation to allow reselection |
| `SelectionChangedCommand` | Fires on selection change to trigger navigation |

**Important:** Set `IsRefreshing = false` in a `finally` block so the spinner always stops, even on error. Reset `SelectedItem = null` after navigating, otherwise tapping the same item again won't trigger the command.
